        new() { Category = "Fall Protection", Description = "Safety nets in place" },
        new() { Category = "Fall Protection", Description = "Harnesses used at height" },
        new() { Category = "Fall Protection", Description = "Ladders secured and inspected" },
        new() { Category = "Fall Protection", Description = "Scaffolding properly erected" },

        // Housekeeping
        new() { Category = "Housekeeping", Description = "Walkways clear of debris" },
        new() { Category = "Housekeeping", Description = "Materials stored properly" },
        new() { Category = "Housekeeping", Description = "Waste containers available" },
        new() { Category = "Housekeeping", Description = "No tripping hazards" },

        // Electrical
        new() { Category = "Electrical", Description = "Temporary wiring in good condition" },
        new() { Category = "Electrical", Description = "GFCIs in use" },
        new() { Category = "Electrical", Description = "Electrical panels accessible" },
        new() { Category = "Electrical", Description = "No exposed wiring" },

        // Fire Safety
        new() { Category = "Fire Safety", Description = "Fire extinguishers accessible" },
        new() { Category = "Fire Safety", Description = "Hot work permits in place" },
        new() { Category = "Fire Safety", Description = "Flammable materials stored safely" },
        new() { Category = "Fire Safety", Description = "Emergency exits clear" },

        // Equipment
        new() { Category = "Equipment", Description = "Machinery guards in place" },
        new() { Category = "Equipment", Description = "Equipment inspections current" },
        new() { Category = "Equipment", Description = "Operators certified" },
        new() { Category = "Equipment", Description = "Lockout/tagout procedures followed" },

        // Excavation
        new() { Category = "Excavation", Description = "Trenches properly shored" },
        new() { Category = "Excavation", Description = "Spoil piles set back from edge" },
        new() { Category = "Excavation", Description = "Access/egress provided" },

        // Signage & Barriers
        new() { Category = "Signage & Barriers", Description = "Warning signs posted" },
        new() { Category = "Signage & Barriers", Description = "Barricades around hazards" },
        new() { Category = "Signage & Barriers", Description = "Site perimeter secured" },
    };
}

