using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class LocalStorageService : ILocalStorageService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public LocalStorageService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        await _js.InvokeVoidAsync("indexedDbStorage.initialize");
    }

    // Sites
    public async Task<List<Site>> GetAllSitesAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "sites");
        return Deserialize<List<Site>>(items);
    }

    public async Task<Site?> GetSiteAsync(string id)
    {
        var item = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "sites", id);
        return item.HasValue ? Deserialize<Site>(item.Value) : null;
    }

    public async Task SaveSiteAsync(Site site)
    {
        var data = SerializeToElement(site);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "sites", data);
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbStorage.deleteItem", "sites", id);
    }

    // Inspections
    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getAllItems", "inspections");
        return Deserialize<List<Inspection>>(items);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getByIndex", "inspections", "siteId", siteId);
        return Deserialize<List<Inspection>>(items);
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var item = await _js.InvokeAsync<JsonElement?>("indexedDbStorage.getItem", "inspections", id);
        return item.HasValue ? Deserialize<Inspection>(item.Value) : null;
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var data = SerializeToElement(inspection);
        await _js.InvokeVoidAsync("indexedDbStorage.putItem", "inspections", data);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("indexedDbStorage.deleteItem", "inspections", id);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbStorage.getUnsyncedInspections");
        return Deserialize<List<Inspection>>(items);
    }

    public async Task MarkAsSyncedAsync(string inspectionId)
    {
        var inspection = await GetInspectionAsync(inspectionId);
        if (inspection is not null)
        {
            inspection.IsSynced = true;
            await SaveInspectionAsync(inspection);
        }
    }

    private static T Deserialize<T>(JsonElement element) where T : new()
    {
        return JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions) ?? new T();
    }

    private static JsonElement SerializeToElement<T>(T obj)
    {
        var json = JsonSerializer.Serialize(obj, JsonOptions);
        return JsonDocument.Parse(json).RootElement.Clone();
    }
}

using Microsoft.JSInterop;

namespace SiteInspector.Client.Services;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;

    public bool IsOnline { get; private set; } = true;
    public event Action<bool>? OnConnectivityChanged;

    public ConnectivityService(IJSRuntime js)
    {
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("navigator.onLine.valueOf");
        await _js.InvokeVoidAsync("eval", $@"
            window.addEventListener('online', () => DotNet.invokeMethodAsync('SiteInspector.Client', 'OnConnectivityChanged', true));
            window.addEventListener('offline', () => DotNet.invokeMethodAsync('SiteInspector.Client', 'OnConnectivityChanged', false));
        ");
    }

    [JSInvokable("OnConnectivityChanged")]
    public static void HandleConnectivityChange(bool isOnline)
    {
        _staticInstance?.SetOnline(isOnline);
    }

    private static ConnectivityService? _staticInstance;

    public void RegisterAsStatic()
    {
        _staticInstance = this;
    }

    private void SetOnline(bool isOnline)
    {
        IsOnline = isOnline;
        OnConnectivityChanged?.Invoke(isOnline);
    }

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        if (_staticInstance == this)
            _staticInstance = null;
    }
}

using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService : IAsyncDisposable
{
    private readonly ILocalStorageService _storage;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private readonly PeriodicTimer _timer;
    private CancellationTokenSource? _cts;

    public int PendingSyncCount { get; private set; }
    public DateTime? LastSyncTime { get; private set; }
    public event Action? OnSyncStatusChanged;

    public SyncService(ILocalStorageService storage, ConnectivityService connectivity, HttpClient http)
    {
        _storage = storage;
        _connectivity = connectivity;
        _http = http;
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(30));
    }

    public async Task StartAsync()
    {
        _connectivity.OnConnectivityChanged += OnConnectivityChanged;
        _cts = new CancellationTokenSource();
        await UpdatePendingCount();
        _ = RunSyncLoop(_cts.Token);
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    private async Task RunSyncLoop(CancellationToken ct)
    {
        while (await _timer.WaitForNextTickAsync(ct))
        {
            if (_connectivity.IsOnline)
            {
                await TrySyncAsync();
            }
            else
            {
                await UpdatePendingCount();
            }
        }
    }

    public async Task TrySyncAsync()
    {
        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            PendingSyncCount = unsynced.Count;
            OnSyncStatusChanged?.Invoke();

            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections/sync", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        await _storage.MarkAsSyncedAsync(inspection.Id);
                        PendingSyncCount--;
                        OnSyncStatusChanged?.Invoke();
                    }
                }
                catch
                {
                    // Server unreachable — stop trying until next cycle
                    break;
                }
            }

            if (PendingSyncCount == 0)
            {
                LastSyncTime = DateTime.UtcNow;
            }
            OnSyncStatusChanged?.Invoke();
        }
        catch
        {
            // Storage access failed — retry next cycle
        }
    }

    private async Task UpdatePendingCount()
    {
        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            PendingSyncCount = unsynced.Count;
            OnSyncStatusChanged?.Invoke();
        }
        catch { }
    }

    public async ValueTask DisposeAsync()
    {
        _connectivity.OnConnectivityChanged -= OnConnectivityChanged;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer.Dispose();
    }
}

