+                store.createIndex('isSynced', 'isSynced', { unique: false });
+            }
+        };
+        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
+        request.onerror = (e) => reject(e.target.error);
+    });
+}
+
+function toStore(storeName, mode) {
+    return db.transaction(storeName, mode).objectStore(storeName);
+}
+
+function promisifyRequest(request) {
+    return new Promise((resolve, reject) => {
+        request.onsuccess = () => resolve(request.result);
+        request.onerror = () => reject(request.error);
+    });
+}
+
+window.indexedDbStorage = {
+    initialize: async function () {
+        await openDb();
+    },
+
+    putItem: async function (storeName, item) {
+        await openDb();
+        const store = toStore(storeName, 'readwrite');
+        await promisifyRequest(store.put(item));
+    },
+
+    getItem: async function (storeName, id) {
+        await openDb();
+        const store = toStore(storeName, 'readonly');
+        return await promisifyRequest(store.get(id));
+    },
+
+    getAllItems: async function (storeName) {
+        await openDb();
+        const store = toStore(storeName, 'readonly');
+        return await promisifyRequest(store.getAll());
+    },
+
+    deleteItem: async function (storeName, id) {
+        await openDb();
+        const store = toStore(storeName, 'readwrite');
+        await promisifyRequest(store.delete(id));
+    },
+
+    getByIndex: async function (storeName, indexName, value) {
+        await openDb();
+        const store = toStore(storeName, 'readonly');
+        const index = store.index(indexName);
+        return await promisifyRequest(index.getAll(value));
+    },
+
+    getUnsyncedInspections: async function () {
+        await openDb();
+        const store = toStore('inspections', 'readonly');
+        const index = store.index('isSynced');
+        return await promisifyRequest(index.getAll(false));
+    }
+};
