@page "/"
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Site Inspector</PageTitle>

<div class="page-header">
    <h1>Construction Sites</h1>
    <button class="btn-primary" @onclick="ShowAddSite">+ Add Site</button>
</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <input @bind="_newSiteName" @bind:event="oninput" placeholder="Site name" class="input-field" />
        <input @bind="_newSiteAddress" @bind:event="oninput" placeholder="Address" class="input-field" />
        <div class="form-actions">
            <button class="btn-primary" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
            <button class="btn-secondary" @onclick="CancelAdd">Cancel</button>
        </div>
    </div>
}

@if (_sites is null)
{
    <div class="loading">Loading sites...</div>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <p>No construction sites yet.</p>
        <p>Tap <strong>+ Add Site</strong> to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="site-card" @onclick="() => OpenSite(site.Id)">
                <div class="site-info">
                    <h3>@site.Name</h3>
                    <p>@site.Address</p>
                </div>
                <span class="chevron">›</span>
            </div>
        }
    </div>
}

@code {
    private List<Site>? _sites;
    private bool _showAddForm;
    private string _newSiteName = string.Empty;
    private string _newSiteAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _sites = await Storage.GetAllSitesAsync();
    }

    private void ShowAddSite() => _showAddForm = true;
    private void CancelAdd()
    {
        _showAddForm = false;
        _newSiteName = string.Empty;
        _newSiteAddress = string.Empty;
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new Site
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };
        await Storage.SaveSiteAsync(site);
        _sites = await Storage.GetAllSitesAsync();
        CancelAdd();
    }

    private void OpenSite(string siteId)
    {
        Nav.NavigateTo($"/site/{siteId}");
    }
}

@page "/site/{SiteId}"
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>@(_site?.Name ?? "Site")</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@(_site?.Name ?? "Loading...")</h1>
</div>

@if (_site is not null)
{
    <div class="site-detail-header">
        <p class="site-address">@_site.Address</p>
        <button class="btn-primary btn-large" @onclick="StartNewInspection">
            📋 New Inspection
        </button>
    </div>
}

@if (_inspections is not null)
{
    <h2>Inspection History</h2>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections yet for this site.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
            {
                <div class="inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                    <div class="inspection-info">
                        <div class="inspection-date">@inspection.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</div>
                        <div class="inspection-meta">
                            <span class="status-badge @inspection.Status.ToString().ToLower()">
                                @inspection.Status
                            </span>
                            @if (!inspection.IsSynced)
                            {
                                <span class="sync-badge pending">⏳ Not synced</span>
                            }
                            else
                            {
                                <span class="sync-badge synced">✓ Synced</span>
                            }
                        </div>
                        <div class="inspection-summary">
                            @{
                                var completed = inspection.ChecklistItems.Count(i => i.Result != ChecklistResult.NotInspected);
                                var total = inspection.ChecklistItems.Count;
                                var failed = inspection.ChecklistItems.Count(i => i.Result == ChecklistResult.Fail);
                            }
                            <span>@completed/@total items checked</span>
                            @if (failed > 0)
                            {
                                <span class="fail-count">@failed failed</span>
                            }
                        </div>
                    </div>
                    <span class="chevron">›</span>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private Site? _site;
    private List<Inspection>? _inspections;

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _site = await Storage.GetSiteAsync(SiteId);
        _inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "Unknown",
            ChecklistItems = ChecklistTemplate.GetDefaultChecklist()
        };
        await Storage.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private void OpenInspection(string id)
    {
        Nav.NavigateTo($"/inspection/{id}");
    }
}

@page "/inspection/{InspectionId}"
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>Inspection</PageTitle>

@if (_inspection is null)
{
    <div class="loading">Loading inspection...</div>
}
else
{
    <div class="page-header">
        <button class="btn-back" @onclick="GoBack">← Back</button>
        <h1>@_inspection.SiteName</h1>
    </div>

    <div class="inspection-tabs">
        <button class="tab @(_activeTab == Tab.Checklist ? "active" : "")" @onclick="() => _activeTab = Tab.Checklist">
            Checklist
        </button>
        <button class="tab @(_activeTab == Tab.Notes ? "active" : "")" @onclick="() => _activeTab = Tab.Notes">
            Notes
        </button>
        <button class="tab @(_activeTab == Tab.Photos ? "active" : "")" @onclick="() => _activeTab = Tab.Photos">
            Photos (@_inspection.Photos.Count)
        </button>
    </div>

    @if (_activeTab == Tab.Checklist)
    {
        <div class="checklist-container">
            @foreach (var category in _inspection.ChecklistItems.GroupBy(i => i.Category))
            {
                <div class="checklist-category">
                    <h3>@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @item.Result.ToString().ToLower()">
                            <div class="checklist-description">@item.Description</div>
                            <div class="checklist-buttons">
                                <button class="result-btn pass @(item.Result == ChecklistResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, ChecklistResult.Pass)">✓</button>
                                <button class="result-btn fail @(item.Result == ChecklistResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, ChecklistResult.Fail)">✗</button>
                                <button class="result-btn na @(item.Result == ChecklistResult.NotApplicable ? "selected" : "")"
                                        @onclick="() => SetResult(item, ChecklistResult.NotApplicable)">N/A</button>
                            </div>
                            @if (item.Result == ChecklistResult.Fail)
                            {
                                <input class="item-note" placeholder="Add note about failure..."
                                       value="@item.Notes"
                                       @onchange="(e) => SetItemNote(item, e.Value?.ToString() ?? string.Empty)" />
                            }
                        </div>
                    }
                </div>
            }
        </div>

        <div class="checklist-footer">
            @{
                var completed = _inspection.ChecklistItems.Count(i => i.Result != ChecklistResult.NotInspected);
                var total = _inspection.ChecklistItems.Count;
            }
            <div class="progress-bar">
                <div class="progress-fill" style="width: @(total > 0 ? (completed * 100 / total) : 0)%"></div>
            </div>
            <span class="progress-text">@completed / @total items</span>
        </div>
    }
    else if (_activeTab == Tab.Notes)
    {
        <div class="notes-container">
            <label>Inspector Name</label>
            <input class="input-field" placeholder="Your name"
                   value="@_inspection.InspectorName"
                   @onchange="(e) => UpdateInspectorName(e.Value?.ToString() ?? string.Empty)" />

            <label>General Notes</label>
            <textarea class="input-field notes-textarea" placeholder="Add observations, concerns, or follow-up items..."
                      @onchange="(e) => UpdateNotes(e.Value?.ToString() ?? string.Empty)">@_inspection.Notes</textarea>
        </div>
    }
    else if (_activeTab == Tab.Photos)
    {
        <div class="photos-container">
            <label class="photo-upload-btn">
                📷 Take Photo / Upload
                <InputFile OnChange="HandlePhotoUpload" accept="image/*" capture="environment" multiple />
            </label>

            @if (_inspection.Photos.Count == 0)
            {
                <div class="empty-state">
                    <p>No photos attached yet.</p>
                    <p>Tap the button above to add photos.</p>
                </div>
            }
            else
            {
                <div class="photo-grid">
                    @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.CapturedAt))
                    {
                        <div class="photo-card">
                            <img src="data:@photo.ContentType;base64,@photo.Base64Data" alt="@photo.Caption" />
                            <input class="photo-caption" placeholder="Add caption..."
                                   value="@photo.Caption"
                                   @onchange="(e) => UpdatePhotoCaption(photo, e.Value?.ToString() ?? string.Empty)" />
                            <button class="btn-danger-small" @onclick="() => RemovePhoto(photo)">Remove</button>
                        </div>
                    }
                </div>
            }
        </div>
    }

    <div class="inspection-actions">
        @if (_inspection.Status == InspectionStatus.InProgress)
        {
            <button class="btn-success btn-large" @onclick="CompleteInspection">
                ✓ Complete Inspection
            </button>
        }
        else
        {
            <div class="completed-badge">✓ Inspection Completed @_inspection.CompletedAt?.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</div>
        }
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;
    private Tab _activeTab = Tab.Checklist;
    private bool _saveScheduled;

    private enum Tab { Checklist, Notes, Photos }

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _inspection = await Storage.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, ChecklistResult result)
    {
        item.Result = item.Result == result ? ChecklistResult.NotInspected : result;
        await ScheduleSave();
    }

    private async Task SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await ScheduleSave();
    }

    private async Task UpdateInspectorName(string name)
    {
        if (_inspection is null) return;
        _inspection.InspectorName = name;
        await ScheduleSave();
    }

    private async Task UpdateNotes(string notes)
    {
        if (_inspection is null) return;
        _inspection.Notes = notes;
        await ScheduleSave();
    }

    private async Task HandlePhotoUpload(InputFileChangeEventArgs e)
    {
        if (_inspection is null) return;

        foreach (var file in e.GetMultipleFiles(10))
        {
            // Limit to 5MB per photo
            using var stream = file.OpenReadStream(5 * 1024 * 1024);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);
            var base64 = Convert.ToBase64String(ms.ToArray());

            _inspection.Photos.Add(new InspectionPhoto
            {
                FileName = file.Name,
                ContentType = file.ContentType,
                Base64Data = base64
            });
        }

        await ScheduleSave();
    }

    private async Task UpdatePhotoCaption(InspectionPhoto photo, string caption)
    {
        photo.Caption = caption;
        await ScheduleSave();
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection?.Photos.Remove(photo);
        await ScheduleSave();
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        _inspection.CompletedAt = DateTime.UtcNow;
        await SaveNow();
    }

    private async Task ScheduleSave()
    {
        // Save immediately for offline reliability
        await SaveNow();
    }

    private async Task SaveNow()
    {
        if (_inspection is null) return;
        _inspection.IsSynced = false;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private void GoBack()
    {
        if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }
}

