    private bool _saveScheduled;

    private enum Tab { Checklist, Notes, Photos }

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        _inspection = await Storage.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, ChecklistResult result)
    {
        item.Result = item.Result == result ? ChecklistResult.NotInspected : result;
        await ScheduleSave();
    }

    private async Task SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await ScheduleSave();
    }

    private async Task UpdateInspectorName(string name)
    {
        if (_inspection is null) return;
        _inspection.InspectorName = name;
        await ScheduleSave();
    }

    private async Task UpdateNotes(string notes)
    {
        if (_inspection is null) return;
        _inspection.Notes = notes;
        await ScheduleSave();
    }

    private async Task HandlePhotoUpload(InputFileChangeEventArgs e)
    {
        if (_inspection is null) return;

        foreach (var file in e.GetMultipleFiles(10))
        {
            // Limit to 5MB per photo
            using var stream = file.OpenReadStream(5 * 1024 * 1024);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);
            var base64 = Convert.ToBase64String(ms.ToArray());

            _inspection.Photos.Add(new InspectionPhoto
            {
                FileName = file.Name,
                ContentType = file.ContentType,
                Base64Data = base64
            });
        }

        await ScheduleSave();
    }

    private async Task UpdatePhotoCaption(InspectionPhoto photo, string caption)
    {
        photo.Caption = caption;
        await ScheduleSave();
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection?.Photos.Remove(photo);
        await ScheduleSave();
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        _inspection.CompletedAt = DateTime.UtcNow;
        await SaveNow();
    }

    private async Task ScheduleSave()
    {
        // Save immediately for offline reliability
        await SaveNow();
    }

    private async Task SaveNow()
    {
        if (_inspection is null) return;
        _inspection.IsSynced = false;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private void GoBack()
    {
        if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }
}

