        _showAddForm = false;
        _newSiteName = string.Empty;
        _newSiteAddress = string.Empty;
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new Site
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };
        await Storage.SaveSiteAsync(site);
        _sites = await Storage.GetAllSitesAsync();
        CancelAdd();
    }

    private void OpenSite(string siteId)
    {
        Nav.NavigateTo($"/site/{siteId}");
    }
}

@page "/site/{SiteId}"
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<PageTitle>@(_site?.Name ?? "Site")</PageTitle>

<div class="page-header">
    <button class="btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@(_site?.Name ?? "Loading...")</h1>
</div>

@if (_site is not null)
{
    <div class="site-detail-header">
        <p class="site-address">@_site.Address</p>
        <button class="btn-primary btn-large" @onclick="StartNewInspection">
            📋 New Inspection
        </button>
    </div>
}

@if (_inspections is not null)
{
    <h2>Inspection History</h2>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections yet for this site.</p>
        </div>
    }
    else
    {
        <div class="inspection-list">
            @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
            {
                <div class="inspection-card" @onclick="() => OpenInspection(inspection.Id)">
                    <div class="inspection-info">
                        <div class="inspection-date">@inspection.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</div>
                        <div class="inspection-meta">
                            <span class="status-badge @inspection.Status.ToString().ToLower()">
                                @inspection.Status
                            </span>
                            @if (!inspection.IsSynced)
                            {
                                <span class="sync-badge pending">⏳ Not synced</span>
                            }
                            else
                            {
                                <span class="sync-badge synced">✓ Synced</span>
                            }
                        </div>
                        <div class="inspection-summary">
                            @{
                                var completed = inspection.ChecklistItems.Count(i => i.Result != ChecklistResult.NotInspected);
