@inherits LayoutComponentBase
@inject SyncService Sync
@inject ConnectivityService Connectivity
@implements IDisposable

<div class="app-container">
    <header class="app-header">
        <div class="header-left">
            <span class="app-title">🏗️ Site Inspector</span>
        </div>
        <div class="header-right">
            <span class="connectivity-indicator @(Connectivity.IsOnline ? "online" : "offline")">
                @(Connectivity.IsOnline ? "●" : "○")
            </span>
            @if (Sync.PendingSyncCount > 0)
            {
                <span class="sync-count" title="@Sync.PendingSyncCount items pending sync">
                    @Sync.PendingSyncCount ⏳
                </span>
            }
        </div>
    </header>

    <main class="app-main">
        @Body
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    protected override void OnInitialized()
    {
        Sync.OnSyncStatusChanged += StateHasChanged;
        Connectivity.OnConnectivityChanged += OnConnectivityChanged;
    }

    private void OnConnectivityChanged(bool _) => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        Sync.OnSyncStatusChanged -= StateHasChanged;
        Connectivity.OnConnectivityChanged -= OnConnectivityChanged;
    }
}

