using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using SiteInspector.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<ILocalStorageService, LocalStorageService>();
builder.Services.AddScoped<ConnectivityService>();
builder.Services.AddScoped<SyncService>();

var host = builder.Build();

// Initialize connectivity monitoring and sync
var connectivity = host.Services.GetRequiredService<ConnectivityService>();
connectivity.RegisterAsStatic();
await connectivity.InitializeAsync();

var sync = host.Services.GetRequiredService<SyncService>();
await sync.StartAsync();

await host.RunAsync();

