using System.Text.Json;

namespace SiteInspector.Endpoints;

public static class SyncEndpoints
{
    private static readonly string DataDir = Path.Combine(
        Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
        "SiteInspector", "Inspections");

    public static void MapSyncEndpoints(this WebApplication app)
    {
        app.MapPost("/api/inspections/sync", async (HttpContext context) =>
        {
            Directory.CreateDirectory(DataDir);

            using var reader = new StreamReader(context.Request.Body);
            var json = await reader.ReadToEndAsync();

            var doc = JsonDocument.Parse(json);
            var id = doc.RootElement.GetProperty("id").GetString() ?? Guid.NewGuid().ToString();
            var filePath = Path.Combine(DataDir, $"{id}.json");
            await File.WriteAllTextAsync(filePath, json);

            return Results.Ok(new { id, syncedAt = DateTime.UtcNow });
        });

        app.MapGet("/api/inspections", () =>
        {
            Directory.CreateDirectory(DataDir);
            var files = Directory.GetFiles(DataDir, "*.json");
            var inspections = files.Select(f => JsonDocument.Parse(File.ReadAllText(f)).RootElement).ToList();
            return Results.Ok(inspections);
        });
    }
}

